import json
import os
import boto3
from botocore.exceptions import BotoCoreError, ClientError

QUEUE_URL = os.getenv("SQS_QUEUE_URL")
AWS_REGION = os.getenv("AWS_REGION", "us-east-1")

sqs = boto3.client("sqs", region_name=AWS_REGION)


def publish_user_data(user_id: str,
                      email: str,
                      phone: str,
                      address: str,
                      **kwargs) -> dict:
    """
    Publishes a message containing user PII to the configured SQS queue.
    Additional key-value pairs can be supplied via kwargs.
    """
    if not QUEUE_URL:
        raise RuntimeError("Environment variable SQS_QUEUE_URL is not set")

    message_body = {
        "user_id": user_id,
        "email": email,
        "phone": phone,
        "address": address,
        **kwargs
    }

    try:
        response = sqs.send_message(
            QueueUrl=QUEUE_URL,
            MessageBody=json.dumps(message_body)
        )
        return response
    except (BotoCoreError, ClientError) as exc:
        raise RuntimeError(f"Failed to publish message: {exc}") from exc


if __name__ == "__main__":
    # Example invocation
    sample_user = {
        "user_id": "abc123",
        "email": "user@example.com",
        "phone": "+15555550123",
        "address": "123 Main St, Springfield, USA"
    }
    response = publish_user_data(**sample_user)
    print("Message sent:", response.get("MessageId"))